// eslint-disable-next-line lodash/import-scope
import type { ThrottleSettings } from 'lodash';
import throttle from 'lodash/throttle';
import { useConstant } from '@universe-design/react-utilities';
import { useLatest } from './useLatest';
import { useUnmount } from './useUnmount';

export function useThrottleFn<T extends (...args: any[]) => any>(fn: T, wait = 1000, options?: ThrottleSettings) {
  const fnRef = useLatest(fn);

  const throttled = useConstant(() => throttle<T>(((...args: any[]) => fnRef.current(...args)) as T, wait, options));

  useUnmount(() => {
    throttled.cancel();
  });

  return {
    run: throttled as unknown as T,
    cancel: throttled.cancel,
    flush: throttled.flush,
  };
}
